// ── Extraire le body ────────────────────────────────────────────────────────
const body = $input.item.json.body || $input.item.json;

const student_id       = body.student_id       || null;
const description      = body.prompt || body.message || body.description || body.idee || '';
const type_publication = (body.type_publication || body.type || 'DEMANDE_SERVICE').toUpperCase();
const localisation     = body.localisation || '';
const image_url        = body.image_url    || null;
const prix_input       = parseFloat(body.prix_vente || body.budget || 0);

// ── Validation ───────────────────────────────────────────────────────────────
const errors = [];

if (!student_id || isNaN(parseInt(student_id))) {
  errors.push('student_id est requis (entier)');
}
if (!description || description.trim().length < 5) {
  errors.push('description/prompt est requis (minimum 5 caractères)');
}

const typesValides = ['OFFRE_SERVICE', 'DEMANDE_SERVICE', 'VENTE_OBJET'];
if (!typesValides.includes(type_publication)) {
  errors.push('type_publication invalide. Valeurs : ' + typesValides.join(', '));
}

if (errors.length > 0) {
  return { json: { valid: false, errors, message: 'Validation échouée' } };
}

// ── Label humain ─────────────────────────────────────────────────────────────
const typeLabel = {
  'DEMANDE_SERVICE': "demande de service (l'étudiant cherche quelqu'un pour l'aider)",
  'VENTE_OBJET':     "vente d'objet (l'étudiant vend quelque chose)",
  'OFFRE_SERVICE':   "offre de service (l'étudiant propose ses compétences)"
}[type_publication];

// ── Prompt Claude ────────────────────────────────────────────────────────────
const prompt = `Tu es un assistant pour CampusLink, plateforme d'entraide étudiante.

Un étudiant veut créer une publication de type : "${typeLabel}".
Localisation : "${localisation || 'Non précisée'}".
Budget / Prix indicatif : ${prix_input > 0 ? prix_input + '€' : 'non précisé'}.

Voici sa description en langage naturel :
"""${description}"""

Génère une publication structurée et professionnelle.
Réponds UNIQUEMENT avec ce JSON brut (sans markdown, sans backticks) :
{
  "titre": "[titre clair et accrocheur, 10 à 100 caractères]",
  "message": "[description complète, professionnelle et convaincante, 3 à 6 phrases]",
  "prix_vente": [${prix_input > 0 ? prix_input : 'nombre décimal suggéré selon le contexte, 0 si don'}]
}

Règles strictes :
- titre : pas de guillemets, max 100 caractères
- message : bien rédigé, attirant, adapté au type de publication
- prix_vente : nombre décimal uniquement (ex: 25.00), jamais de texte
- Pour DEMANDE_SERVICE : prix = ce que l'étudiant est prêt à payer
- Pour VENTE_OBJET : prix = prix de vente de l'objet
- Pour OFFRE_SERVICE : prix = tarif horaire ou forfait proposé
- Réponds UNIQUEMENT avec le JSON, rien d'autre`;

return {
  json: {
    valid: true,
    prompt,
    meta: {
      student_id:       parseInt(student_id),
      type_publication,
      localisation:     localisation || null,
      image_url:        image_url    || null,
      prix_input
    }
  }
};

// ── Extraire le texte brut d'OpenRouter ─────────────────────────────────────
const body = $input.item.json;
let rawText = '';

try {
  rawText = body.choices[0].message.content || '';
} catch (e) {
  throw new Error('Réponse OpenRouter invalide : ' + JSON.stringify(body).substring(0, 300));
}

console.log('=== OpenRouter response ===');
console.log(rawText);
console.log('===========================');

// ── Récupérer les métadonnées du nœud précédent ──────────────────────────────
const meta = $('Valider & Préparer Prompt').item.json.meta;

// ── Parser le JSON retourné par Claude ───────────────────────────────────────
try {
  let cleaned = rawText.replace(/```json/gi, '').replace(/```/g, '').trim();

  const start = cleaned.indexOf('{');
  const end   = cleaned.lastIndexOf('}');

  if (start === -1 || end === -1) {
    throw new Error('Aucun JSON dans la réponse : ' + cleaned.substring(0, 100));
  }

  const parsed = JSON.parse(cleaned.substring(start, end + 1));

  if (!parsed.titre || !parsed.message) {
    throw new Error('JSON incomplet : titre ou message manquant');
  }

  // Sanitiser le titre (max 200 chars selon la DB)
  const titre   = String(parsed.titre).substring(0, 200).trim();
  const message = String(parsed.message).trim();
  const prix    = parseFloat(parsed.prix_vente) || meta.prix_input || 0;

  return {
    json: {
      ok:               true,
      student_id:       meta.student_id,
      type_publication: meta.type_publication,
      titre,
      message,
      prix_vente:       prix,
      localisation:     meta.localisation || null,
      image_url:        meta.image_url    || null
    }
  };

} catch (e) {
  console.error('Parse error:', e.message);
  // Fallback : utiliser la description brute comme message
  return {
    json: {
      ok:               true,
      student_id:       meta.student_id,
      type_publication: meta.type_publication,
      titre:            'Publication étudiante',
      message:          rawText.substring(0, 500),
      prix_vente:       meta.prix_input || 0,
      localisation:     meta.localisation || null,
      image_url:        meta.image_url    || null
    }
  };
}

// ── Construire la réponse finale ─────────────────────────────────────────────
const db  = $input.item.json;
const pub = $('Parser Réponse Claude').item.json;

// MySQL retourne LAST_INSERT_ID() sous cette clé
const pubId = db['LAST_INSERT_ID()'] || db.publication_id || db.insertId || null;

console.log('Publication insérée, ID =', pubId);

return {
  json: {
    success:        true,
    publication_id: pubId,
    message:        'Publication créée et enregistrée avec succès',
    publication: {
      id:               pubId,
      student_id:       pub.student_id,
      titre:            pub.titre,
      message:          pub.message,
      type_publication: pub.type_publication,
      prix_vente:       pub.prix_vente,
      status:           'ACTIVE',
      localisation:     pub.localisation,
      image_url:        pub.image_url
    }
  }
};

const data = $input.item.json;
return {
  json: {
    success: false,
    message: data.message || 'Validation échouée',
    errors:  data.errors  || []
  }
};

const err = $input.item.json;
const pub = $('Parser Réponse Claude').item.json;

return {
  json: {
    success: false,
    message: 'Erreur lors de l\'insertion en base de données',
    error:   JSON.stringify(err),
    publication_generee: {
      titre:   pub.titre,
      message: pub.message
    }
  }
};
